  const { inline, size } = props;
  const [open, setOpen] = React.useState();

  const contextValue = React.useMemo(() => ({ inline, open }), [inline, open]);
  const state = {
    inline,
    size,
    open,
    // 👇 "contextValue" is a part of component's state
    contextValue,
  };

  return state;
}

function renderBaz(state) {
